/**
 * @fileoverview ArtBoard DOM construction & rendering.
 * @module module/ArtBoard/view
 */

import razyui from '../../index.js';
import {
    CLS, SEL, HANDLE_DIRS, ITEM_TYPE,
    TOOLBAR_ITEMS, DEFAULTS, PART,
} from './constants.js';

/**
 * Build the complete ArtBoard DOM tree.
 *
 * @param {HTMLElement} parent - parent to append into
 * @param {object} config
 * @returns {{ board, viewport, canvas, toolbar, zoomInfo }}
 */
export function buildBoard(parent, config) {
    const board = PART.BOARD.create();
    board.addClass('art-board');

    // ── Viewport (scrollable / pannable area) ──
    const viewport = PART.VIEWPORT.create();

    // ── Canvas (holds items, transforms with zoom/pan) ──
    const canvas = PART.CANVAS.create();
    canvas.css({ width: config.width + 'px', height: config.height + 'px' });

    viewport.append(canvas);

    // ── Toolbar ──
    const toolbar = PART.TOOLBAR.create();
    for (const btn of TOOLBAR_ITEMS) {
        if (btn.type === 'separator') {
            const sep = PART.TOOLBAR_SEP.create();
            toolbar.append(sep);
            continue;
        }
        const el = PART.TOOLBAR_BTN.create({ title: btn.title });
        el[0].innerHTML = btn.icon;
        el.attr('data-action', btn.id);
        toolbar.append(el);
    }

    // ── Zoom info ──
    const zoomInfo = PART.ZOOM_INFO.create({ textContent: '100%' });
    toolbar.append(zoomInfo);

    // ── Grid toggle ──
    if (config.grid) board.addClass(CLS.GRID_VISIBLE);

    board.append(viewport).append(toolbar);
    razyui(parent).append(board);

    return { board, viewport, canvas, toolbar, zoomInfo };
}

/**
 * Create an item DOM element for an image or video.
 *
 * @param {object} itemData - { id, type, src, x, y, w, h, z, label, locked }
 * @returns {HTMLElement} The .ab-item element
 */
export function createItemElement(itemData) {
    const el = PART.ITEM.create();
    el.attr('data-item-id', itemData.id);
    el.css({
        left:   itemData.x + 'px',
        top:    itemData.y + 'px',
        width:  itemData.w + 'px',
        height: itemData.h + 'px',
        'z-index': itemData.z,
    });

    if (itemData.type === ITEM_TYPE.IMAGE) {
        el.addClass(CLS.ITEM_IMAGE);
        const img = razyui.el('img');
        img.attr({ src: itemData.src, alt: itemData.label || '', draggable: 'false', loading: 'lazy' });
        img.css({ width: '100%', height: '100%', 'object-fit': 'cover', 'pointer-events': 'none' });
        // Auto-fit item to image natural aspect ratio once loaded
        img[0].onload = () => {
            const nw = img[0].naturalWidth;
            const nh = img[0].naturalHeight;
            if (nw && nh) {
                const ratio = nw / nh;
                const newH = Math.round(itemData.w / ratio);
                itemData.h = newH;
                el.css('height', newH + 'px');
            }
        };
        el.append(img);
    } else if (itemData.type === ITEM_TYPE.VIDEO) {
        el.addClass(CLS.ITEM_VIDEO);
        const video = razyui.el('video');
        video.attr({ src: itemData.src, preload: 'metadata', muted: '', loop: '', playsinline: '' });
        video.css({ width: '100%', height: '100%', 'object-fit': 'cover', 'pointer-events': 'none' });
        // Auto-fit item to video natural aspect ratio once metadata loaded
        video[0].onloadedmetadata = () => {
            const vw = video[0].videoWidth;
            const vh = video[0].videoHeight;
            if (vw && vh) {
                const ratio = vw / vh;
                const newH = Math.round(itemData.w / ratio);
                itemData.h = newH;
                el.css('height', newH + 'px');
            }
        };
        el.append(video);
    }

    if (itemData.locked) {
        el.addClass(CLS.ITEM_LOCKED);
    }

    return el;
}

/**
 * Add resize handles to a selected item.
 * @param {HTMLElement} el - the .ab-item element (Elements wrapper)
 */
export function addHandles(el) {
    // Remove old handles first
    removeHandles(el);
    for (const dir of HANDLE_DIRS) {
        const handle = PART.HANDLE.create();
        handle.addClass('ab-handle-' + dir);
        handle.attr('data-dir', dir);
        el.append(handle);
    }
}

/**
 * Remove resize handles from an item element.
 * @param {HTMLElement} el - the .ab-item element (Elements wrapper)
 */
export function removeHandles(el) {
    el.find(SEL.HANDLE).each(function () { this.remove(); });
}

/**
 * Update an item element's position/size from item data.
 * @param {HTMLElement} el
 * @param {object} itemData
 */
export function syncItemElement(el, itemData) {
    razyui(el).css({
        left:   itemData.x + 'px',
        top:    itemData.y + 'px',
        width:  itemData.w + 'px',
        height: itemData.h + 'px',
        'z-index': itemData.z,
    });
}

/**
 * Update the canvas transform (pan + zoom).
 * @param {Elements} canvas
 * @param {{ x: number, y: number }} pan
 * @param {number} zoom
 */
export function updateCanvasTransform(canvas, pan, zoom) {
    canvas.css({ transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`, 'transform-origin': '0 0' });
}

/**
 * Mark an item as selected visually.
 * @param {Elements} canvas
 * @param {string} id
 */
export function markSelected(canvas, id) {
    const el = canvas.find(`[data-item-id="${id}"]`);
    el.addClass(CLS.ITEM_SELECTED);
    addHandles(el);
}

/**
 * Clear all selection visuals.
 * @param {Elements} canvas
 */
export function clearSelection(canvas) {
    canvas.find('.' + CLS.ITEM_SELECTED).each(function () {
        const $el = razyui(this);
        $el.removeClass(CLS.ITEM_SELECTED);
        removeHandles($el);
    });
}

/**
 * Update zoom info display.
 * @param {Elements} zoomInfo
 * @param {number} zoom
 */
export function updateZoomDisplay(zoomInfo, zoom) {
    zoomInfo.text(Math.round(zoom * 100) + '%');
}

/**
 * Remove all DOM for cleanup.
 * @param {Elements} board
 */
export function cleanupDOM(board) {
    board?.[0]?.remove();
}
