/**
 * @fileoverview ArtBoard constants — CSS classes, defaults, selectors, item types.
 * @module module/ArtBoard/constants
 */

import Icons from '../Icons.js';
import { defineParts } from '../shared/definePart.js';

// ── Item types ──
export const ITEM_TYPE = Object.freeze({
    IMAGE: 'image',
    VIDEO: 'video',
});

// ── CSS class names ──
export const CLS = Object.freeze({
    BOARD:          'ab-board',
    VIEWPORT:       'ab-viewport',
    CANVAS:         'ab-canvas',
    ITEM:           'ab-item',
    ITEM_SELECTED:  'ab-item-selected',
    ITEM_DRAGGING:  'ab-item-dragging',
    ITEM_RESIZING:  'ab-item-resizing',
    ITEM_IMAGE:     'ab-item-image',
    ITEM_VIDEO:     'ab-item-video',
    ITEM_LOCKED:    'ab-item-locked',
    HANDLE:         'ab-handle',
    SELECTION_BOX:  'ab-selection-box',
    TOOLBAR:        'ab-toolbar',
    TOOLBAR_BTN:    'ab-toolbar-btn',
    TOOLBAR_SEP:    'ab-toolbar-sep',
    GRID_VISIBLE:   'ab-grid-visible',
    PANNING:        'ab-panning',
    HAS_SELECTION:  'ab-has-selection',
    DRAGGING:       'ab-dragging',
    ZOOM_INFO:      'ab-zoom-info',
});

// ── Selectors ──
export const SEL = Object.freeze({
    ITEM:      '.ab-item',
    HANDLE:    '.ab-handle',
    CANVAS:    '.ab-canvas',
    VIEWPORT:  '.ab-viewport',
    TOOLBAR:   '.ab-toolbar',
});

// ── Resize handle directions ──
export const HANDLE_DIRS = Object.freeze(['nw', 'n', 'ne', 'e', 'se', 's', 'sw', 'w']);

// ── Defaults ──
export const DEFAULTS = Object.freeze({
    width:        3000,
    height:       2000,
    zoom:         1,
    minZoom:     0.1,
    maxZoom:     5,
    zoomStep:    0.1,
    grid:         true,
    gridSize:    40,
    snap:         false,
    snapTolerance: 5,
    minItemSize: 20,
    items:       [],
    onSelect:    null,
    onChange:     null,
    onContextMenu: null,
});

// ── Toolbar buttons ──
export const TOOLBAR_ITEMS = Object.freeze([
    { id: 'zoom-in',    icon: Icons.svg('plus', { size: 14, strokeWidth: 2 }),        title: 'Zoom In' },
    { id: 'zoom-out',   icon: Icons.svg('minus', { size: 14, strokeWidth: 2 }),       title: 'Zoom Out' },
    { id: 'zoom-reset', icon: Icons.svg('rotate-ccw', { size: 14, strokeWidth: 1.8 }), title: 'Reset Zoom (100%)' },
    { id: 'sep1',       type: 'separator' },
    { id: 'fit',        icon: Icons.svg('maximize-2', { size: 14, strokeWidth: 1.8 }), title: 'Fit to Screen' },
    { id: 'grid',       icon: Icons.svg('grid', { size: 14, strokeWidth: 1.8 }),       title: 'Toggle Grid' },
    { id: 'sep2',       type: 'separator' },
    { id: 'select-all', icon: Icons.svg('square', { size: 14, strokeWidth: 1.8 }),     title: 'Select All' },
    { id: 'delete',     icon: Icons.svg('x', { size: 14, strokeWidth: 2 }),            title: 'Delete Selected' },
]);

// ── Instance ID counter ──
let _idCounter = 0;
export function nextItemId() { return `ab-item-${++_idCounter}`; }

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('ArtBoard', {
    BOARD       : { class: 'ab-board', aliases: ['board', 'root'] },
    VIEWPORT    : { class: 'ab-viewport', aliases: ['viewport'] },
    CANVAS      : { class: 'ab-canvas', aliases: ['canvas'] },
    ITEM        : { class: 'ab-item', aliases: ['item'] },
    HANDLE      : { class: 'ab-handle', aliases: ['handle'] },
    TOOLBAR     : { class: 'ab-toolbar', aliases: ['toolbar'] },
    TOOLBAR_BTN : { class: 'ab-toolbar-btn', tag: 'button', aliases: ['toolbar-btn'] },
    TOOLBAR_SEP : { class: 'ab-toolbar-sep', tag: 'span', aliases: ['toolbar-sep'] },
    ZOOM_INFO   : { class: 'ab-zoom-info', tag: 'span', aliases: ['zoom-info'] },
});

PART.BOARD.jit    = 'relative w-full h-full flex flex-col overflow-hidden bg-[var(--ab-bg)] fg-[var(--ab-text)] [font-family:inherit]';
PART.VIEWPORT.jit = 'relative flex-1 overflow-hidden cursor-default ^{ab-panning}:[cursor:grabbing]';
PART.CANVAS.jit   = 'absolute [top:0] [left:0] [transform-origin:0_0] ^{ab-grid-visible}:[background-image:linear-gradient(var(--ab-grid-color)_1px,transparent_1px),linear-gradient(90deg,var(--ab-grid-color)_1px,transparent_1px)] ^{ab-grid-visible}:[background-size:var(--ab-grid-size)_var(--ab-grid-size)]';
PART.ITEM.jit     = 'absolute [border:1px_solid_var(--ab-item-border)] rounded-[var(--ab-item-radius)] bg-[var(--ab-item-bg)] [box-shadow:var(--ab-item-shadow)] overflow-hidden [cursor:move] select-none [transition:box-shadow_.15s_cubic-bezier(0.4,0,0.2,1)] hover:[box-shadow:var(--ab-hover-shadow)] {ab-item-selected}:[border-color:var(--ab-select-color)] {ab-item-selected}:[border-width:var(--ab-select-width)] {ab-item-selected}:[box-shadow:0_0_0_1px_var(--ab-select-color),var(--ab-item-shadow)] {ab-item-selected}:hover:[box-shadow:0_0_0_1px_var(--ab-select-color),var(--ab-hover-shadow)] {ab-item-locked}:cursor-default {ab-item-locked}:[opacity:.7] {ab-item-locked}:after:[content:"🔒"] {ab-item-locked}:after:absolute {ab-item-locked}:after:[top:4px] {ab-item-locked}:after:[right:4px] {ab-item-locked}:after:text-[12px] {ab-item-locked}:after:[opacity:.6] {ab-item-dragging}:[opacity:.8] {ab-item-dragging}:[transition:none] [&_img]:block [&_img]:w-full [&_img]:h-full [&_img]:[object-fit:contain] [&_img]:pointer-events-none [&_img]:[border-radius:inherit] [&_video]:block [&_video]:w-full [&_video]:h-full [&_video]:[object-fit:contain] [&_video]:pointer-events-none [&_video]:[border-radius:inherit]';
PART.HANDLE.jit   = 'absolute w-[var(--ab-handle-size)] h-[var(--ab-handle-size)] bg-[var(--ab-select-color)] [border:1px_solid_#fff] rounded-[50%] [z-index:10]'
+ ' {ab-handle-nw}:[top:calc(var(--ab-handle-size)/-2)] {ab-handle-nw}:[left:calc(var(--ab-handle-size)/-2)] {ab-handle-nw}:[cursor:nwse-resize]'
+ ' {ab-handle-n}:[top:calc(var(--ab-handle-size)/-2)] {ab-handle-n}:[left:50%] {ab-handle-n}:[transform:translateX(-50%)] {ab-handle-n}:[cursor:ns-resize]'
+ ' {ab-handle-ne}:[top:calc(var(--ab-handle-size)/-2)] {ab-handle-ne}:[right:calc(var(--ab-handle-size)/-2)] {ab-handle-ne}:[cursor:nesw-resize]'
+ ' {ab-handle-e}:[top:50%] {ab-handle-e}:[right:calc(var(--ab-handle-size)/-2)] {ab-handle-e}:[transform:translateY(-50%)] {ab-handle-e}:[cursor:ew-resize]'
+ ' {ab-handle-se}:[bottom:calc(var(--ab-handle-size)/-2)] {ab-handle-se}:[right:calc(var(--ab-handle-size)/-2)] {ab-handle-se}:[cursor:nwse-resize]'
+ ' {ab-handle-s}:[bottom:calc(var(--ab-handle-size)/-2)] {ab-handle-s}:[left:50%] {ab-handle-s}:[transform:translateX(-50%)] {ab-handle-s}:[cursor:ns-resize]'
+ ' {ab-handle-sw}:[bottom:calc(var(--ab-handle-size)/-2)] {ab-handle-sw}:[left:calc(var(--ab-handle-size)/-2)] {ab-handle-sw}:[cursor:nesw-resize]'
+ ' {ab-handle-w}:[top:50%] {ab-handle-w}:[left:calc(var(--ab-handle-size)/-2)] {ab-handle-w}:[transform:translateY(-50%)] {ab-handle-w}:[cursor:ew-resize]';
PART.TOOLBAR.jit  = 'flex items-center gap-[.25rem] [padding:.25rem_.5rem] bg-[var(--ab-toolbar-bg)] [border-top:1px_solid_var(--ab-toolbar-border)] shrink-0 select-none';
PART.TOOLBAR_BTN.jit = 'inline-flex items-center justify-center w-[28px] h-[28px] [border:1px_solid_rgba(0,0,0,0)] rounded-[4px] [background:rgba(0,0,0,0)] fg-[var(--ab-text)] text-[14px] cursor-pointer [transition:background_.1s_cubic-bezier(0.4,0,0.2,1),border-color_.1s_cubic-bezier(0.4,0,0.2,1)] hover:bg-[var(--ab-btn-hover-bg)] hover:[border-color:var(--ab-toolbar-border)] active:bg-[var(--ab-btn-active-bg)]';
PART.TOOLBAR_SEP.jit = 'inline-block w-[1px] h-[18px] bg-[var(--ab-toolbar-border)] [margin:0_.25rem]';
PART.ZOOM_INFO.jit = 'ml-[auto] text-[.75rem] fg-[var(--ab-text-muted)] [font-variant-numeric:tabular-nums] min-w-[3em] text-right';