/**
 * @fileoverview ArtBoard component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, defaults, toolbar config, item types
 *   helpers.js   — pure geometry utilities (clamp, snap, resize, hit-test)
 *   state.js     — item registry, selection, undo/redo, plugin registry
 *   view.js      — DOM construction, item rendering, canvas transform
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * Features:
 *   - Place images and videos on an infinite-ish canvas
 *   - Pan (middle-click / Alt+drag) and zoom (scroll wheel)
 *   - Drag and resize items with multi-select support
 *   - Optional snap-to-grid
 *   - Undo / redo (Ctrl+Z / Ctrl+Y)
 *   - Keyboard shortcuts: Delete, Ctrl+A, Ctrl+Z/Y
 *   - Drag-and-drop files from OS to add items
 *   - Right-click context menu via plugin system
 *   - Toolbar with zoom, grid toggle, select-all, delete
 *   - Full programmatic API via getControl()
 *
 * Plugin system:
 *   board.use('myPlugin', {
 *       contextMenu(item, selected) {
 *           return [
 *               { label: 'Do something', action(items) { ... } },
 *           ];
 *       }
 *   });
 *
 * @module module/ArtBoard
 */

import { default as razyui } from '../../index.js';
import Icons from '../Icons.js';
import { DEFAULTS, ITEM_TYPE, CLS, nextItemId } from './constants.js';
import { clamp, clientToCanvas } from './helpers.js';
import {
    createState, pushUndo, selectItem, deselectAll, selectAll,
    deleteSelected, nextZ, undo, redo,
} from './state.js';
import {
    buildBoard, createItemElement, syncItemElement,
    markSelected, clearSelection,
    updateCanvasTransform, updateZoomDisplay, cleanupDOM,
} from './view.js';
import { bindEvents } from './events.js';
import { emitEvent } from '../shared/emitEvent.js';

const { isFn, isStr, isPO } = razyui;

/**
 * ArtBoard — Zoomable, pannable canvas for placing images and videos.
 *
 * @param {string|HTMLElement} target — parent element or selector
 * @param {object} config
 * @param {number}  [config.width=3000]       — canvas width
 * @param {number}  [config.height=2000]      — canvas height
 * @param {number}  [config.zoom=1]           — initial zoom
 * @param {boolean} [config.grid=true]        — show grid
 * @param {number}  [config.gridSize=40]      — grid cell size
 * @param {boolean} [config.snap=false]       — snap to grid
 * @param {Array}   [config.items=[]]         — initial items
 * @param {Function} [config.onSelect]        — selection change callback
 * @param {Function} [config.onChange]         — item change callback
 * @param {Function} [config.onContextMenu]   — context menu callback(e, itemId, menuItems)
 */
const ArtBoard = class {
    // ── Private fields ──
    #el = null;
    #board = null;
    #viewport = null;
    #canvas = null;
    #toolbar = null;
    #zoomInfo = null;
    #config = {};
    #state = null;
    #eventAC = new AbortController();
    #zoom = 1;
    #pan = { x: 0, y: 0 };
    #destroyed = false;
    #contextMenu = null;   // ContextMenu instance (lazy-loaded)

    constructor(target, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // Resolve parent
        if (typeof target === 'string') target = razyui(target)[0];
        this.#el = target || document.body;

        this.#zoom = this.#config.zoom;
        this.#state = createState();

        this.#init();
    }

    // ── Initialisation ──────────────────────────────────

    #init() {
        const { board, viewport, canvas, toolbar, zoomInfo } =
            buildBoard(this.#el, this.#config);

        this.#board = board;
        this.#viewport = viewport;
        this.#canvas = canvas;
        this.#toolbar = toolbar;
        this.#zoomInfo = zoomInfo;

        // Apply initial zoom
        updateCanvasTransform(this.#canvas, this.#pan, this.#zoom);
        updateZoomDisplay(this.#zoomInfo, this.#zoom);

        // Bind events first so the board is interactive immediately
        const self = this;
        bindEvents({
            board:    this.#board,
            viewport: this.#viewport,
            canvas:   this.#canvas,
            toolbar:  this.#toolbar,
            zoomInfo: this.#zoomInfo,
            state:    this.#state,
            config:   this.#config,
            getPan:   () => ({ ...self.#pan }),
            setPan:   (p) => { self.#pan = p; },
            getZoom:  () => self.#zoom,
            setZoom:  (z) => { self.#zoom = z; },
            addItemInternal: (cfg) => self.#addItemInternal(cfg),
            rebuildCanvas:   () => self.#rebuildCanvas(),
            onContextMenu:   (e, itemId) => self.#handleContextMenu(e, itemId),
            onSelectionChange: () => {
                const items = self.getSelectedItems();
                emitEvent(self.#viewport[0], 'select', { items });
                self.#config.onSelect?.(items);
            },
            onItemChange: () => {
                const items = self.getSelectedItems();
                emitEvent(self.#viewport[0], 'change', { value: items, items });
                self.#config.onChange?.(items);
            },
        }, this.#eventAC.signal);

        // Defer initial items to next frame so the cloak can reveal first
        if (Array.isArray(this.#config.items) && this.#config.items.length) {
            requestAnimationFrame(() => {
                for (const itemCfg of this.#config.items) {
                    this.#addItemInternal(itemCfg);
                }
            });
        }
    }

    // ── Internal item management ────────────────────────

    #addItemInternal(cfg) {
        const id = cfg.id || nextItemId();
        const z = nextZ(this.#state);
        const itemData = {
            id,
            type:   cfg.type || ITEM_TYPE.IMAGE,
            src:    cfg.src || '',
            x:      cfg.x ?? 0,
            y:      cfg.y ?? 0,
            w:      cfg.w ?? cfg.width ?? 300,
            h:      cfg.h ?? cfg.height ?? 200,
            z,
            label:  cfg.label || '',
            locked: cfg.locked || false,
            meta:   cfg.meta || {},
        };

        this.#state.items.set(id, itemData);
        const el = createItemElement(itemData);
        this.#canvas.append(el);

        // Auto-play videos
        if (itemData.type === ITEM_TYPE.VIDEO) {
            const video = el.find('video')[0];
            if (video) video.play().catch(() => {});
        }

        return itemData;
    }

    #rebuildCanvas() {
        // Clear all item DOM
        this.#canvas.find('.' + CLS.ITEM).each(function () { this.remove(); });
        // Recreate from state
        for (const item of this.#state.items.values()) {
            const el = createItemElement(item);
            this.#canvas.append(el);
            if (item.type === ITEM_TYPE.VIDEO) {
                const video = el.find('video')[0];
                if (video) video.play().catch(() => {});
            }
        }
        clearSelection(this.#canvas);
    }

    // ── Context menu (integrates with ContextMenu + plugins) ──

    async #handleContextMenu(e, itemId) {
        const items = this.#buildContextMenuItems(itemId);

        // Fire user callback first — they can modify/replace items
        if (isFn(this.#config.onContextMenu)) {
            const overridden = this.#config.onContextMenu(e, itemId, items);
            if (overridden === false) return; // cancelled
        }

        // Try to load ContextMenu if available
        if (!this.#contextMenu) {
            try {
                const CM = await razyui.load('ContextMenu');
                if (CM) {
                    this.#contextMenu = new CM(this.#viewport, {
                        trigger: 'manual',
                        items: () => [],
                    });
                }
            } catch {
                // ContextMenu not available — silently ignore
            }
        }

        if (this.#contextMenu) {
            const ctrl = this.#contextMenu.getControl();
            ctrl.update(items);
            ctrl.open(e.clientX, e.clientY, e.target);
        }
    }

    #buildContextMenuItems(itemId) {
        const self = this;
        const item = itemId ? this.#state.items.get(itemId) : null;
        const selected = this.getSelectedItems();
        const items = [];

        if (item) {
            // Item-level actions
            items.push(
                {
                    label: 'Bring to Front',
                    icon: Icons.svg('arrow-up', { size: 14, strokeWidth: 1.5 }),
                    action() {
                        item.z = nextZ(self.#state);
                        self.#canvas.find(`[data-item-id="${itemId}"]`).css('z-index', item.z);
                    },
                },
                {
                    label: 'Send to Back',
                    icon: Icons.svg('arrow-down', { size: 14, strokeWidth: 1.5 }),
                    action() {
                        item.z = 0;
                        self.#canvas.find(`[data-item-id="${itemId}"]`).css('z-index', 0);
                    },
                },
                { divider: true },
                {
                    label: item.locked ? 'Unlock' : 'Lock',
                    icon: item.locked ? Icons.svg('unlock', { size: 14, strokeWidth: 1.5 }) : Icons.svg('lock', { size: 14, strokeWidth: 1.5 }),
                    action() {
                        item.locked = !item.locked;
                        const el = self.#canvas.find(`[data-item-id="${itemId}"]`);
                        el.toggleClass(CLS.ITEM_LOCKED, item.locked);
                    },
                },
                { divider: true },
                {
                    label: 'Delete',
                    icon: Icons.svg('trash-2', { size: 14, strokeWidth: 1.5 }),
                    action() {
                        pushUndo(self.#state);
                        self.#state.items.delete(itemId);
                        self.#state.selected.delete(itemId);
                        self.#canvas.find(`[data-item-id="${itemId}"]`).each(function () { this.remove(); });
                        const selected = self.getSelectedItems();
                        emitEvent(self.#viewport[0], 'select', { items: selected });
                        self.#config.onSelect?.(selected);
                    },
                },
            );
        } else {
            // Board-level actions
            items.push(
                {
                    label: 'Select All',
                    icon: Icons.svg('square', { size: 14, strokeWidth: 1.5 }),
                    action() {
                        selectAll(self.#state);
                        clearSelection(self.#canvas);
                        for (const id of self.#state.selected) markSelected(self.#canvas, id);
                        const selected = self.getSelectedItems();
                        emitEvent(self.#viewport[0], 'select', { items: selected });
                        self.#config.onSelect?.(selected);
                    },
                },
                {
                    label: 'Fit to Screen',
                    icon: Icons.svg('maximize-2', { size: 14, strokeWidth: 1.5 }),
                    action() {
                        // Trigger toolbar fit
                        self.#toolbar.find('[data-action="fit"]')[0]?.click();
                    },
                },
                {
                    label: self.#board[0]?.classList.contains(CLS.GRID_VISIBLE) ?
                           'Hide Grid' : 'Show Grid',
                    icon: Icons.svg('grid', { size: 14, strokeWidth: 1.5 }),
                    action() {
                        self.#board.toggleClass(CLS.GRID_VISIBLE);
                    },
                },
            );
        }

        // ── Plugin context menu items ──
        for (const [name, plugin] of this.#state.plugins) {
            if (isFn(plugin.contextMenu)) {
                const pluginItems = plugin.contextMenu(item, selected);
                if (Array.isArray(pluginItems) && pluginItems.length) {
                    items.push({ divider: true });
                    items.push(...pluginItems);
                }
            }
        }

        return items;
    }

    // ── Plugin system ───────────────────────────────────

    /**
     * Register a plugin that can extend the context menu and behaviour.
     *
     * @param {string} name - unique plugin name
     * @param {object} plugin - plugin object
     * @param {Function} [plugin.contextMenu] - (item, selected) → Array of menu items
     * @param {Function} [plugin.onAdd]    - called when an item is added
     * @param {Function} [plugin.onRemove] - called when an item is removed
     * @param {Function} [plugin.init]     - called once on registration
     */
    use(name, plugin) {
        if (this.#state.plugins.has(name)) return; // idempotent
        this.#state.plugins.set(name, plugin);
        if (isFn(plugin.init)) {
            plugin.init(this.getControl());
        }
    }

    // ── Public API ──────────────────────────────────────

    /**
     * Add an image to the board.
     * @param {string} src - image URL
     * @param {object} [opts] - { x, y, w, h, label, locked, meta }
     * @returns {object} item data
     */
    addImage(src, opts = {}) {
        pushUndo(this.#state);
        const item = this.#addItemInternal({
            type: ITEM_TYPE.IMAGE,
            src,
            ...opts,
        });
        emitEvent(this.#viewport[0], 'change', { value: [item], items: [item] });
        this.#config.onChange?.([item]);
        return { ...item };
    }

    /**
     * Add a video to the board.
     * @param {string} src - video URL
     * @param {object} [opts] - { x, y, w, h, label, locked, meta }
     * @returns {object} item data
     */
    addVideo(src, opts = {}) {
        pushUndo(this.#state);
        const item = this.#addItemInternal({
            type: ITEM_TYPE.VIDEO,
            src,
            ...opts,
        });
        emitEvent(this.#viewport[0], 'change', { value: [item], items: [item] });
        this.#config.onChange?.([item]);
        return { ...item };
    }

    /**
     * Remove an item by ID.
     * @param {string} id
     */
    removeItem(id) {
        pushUndo(this.#state);
        this.#state.items.delete(id);
        this.#state.selected.delete(id);
        this.#canvas.find(`[data-item-id="${id}"]`).each(function () { this.remove(); });
    }

    /**
     * Update an item's properties.
     * @param {string} id
     * @param {object} props - { x, y, w, h, src, label, locked, meta }
     */
    updateItem(id, props) {
        const item = this.#state.items.get(id);
        if (!item) return;

        pushUndo(this.#state);
        Object.assign(item, props);

        const el = this.#canvas.find(`[data-item-id="${id}"]`);
        if (el.length) {
            syncItemElement(el[0], item);
            // Update src if changed
            if (props.src) {
                if (item.type === ITEM_TYPE.IMAGE) {
                    const img = el.find('img')[0];
                    if (img) img.src = props.src;
                } else if (item.type === ITEM_TYPE.VIDEO) {
                    const video = el.find('video')[0];
                    if (video) video.src = props.src;
                }
            }
            if (props.locked !== undefined) {
                el.toggleClass(CLS.ITEM_LOCKED, props.locked);
            }
        }
    }

    /**
     * Get an item by ID.
     * @param {string} id
     * @returns {object|undefined}
     */
    getItem(id) {
        const item = this.#state.items.get(id);
        return item ? { ...item } : undefined;
    }

    /**
     * Get all items.
     * @returns {object[]}
     */
    getItems() {
        return [...this.#state.items.values()].map(i => ({ ...i }));
    }

    /**
     * Get currently selected items.
     * @returns {object[]}
     */
    getSelectedItems() {
        const result = [];
        for (const id of this.#state.selected) {
            const item = this.#state.items.get(id);
            if (item) result.push({ ...item });
        }
        return result;
    }

    /**
     * Get selected item IDs.
     * @returns {string[]}
     */
    getSelection() {
        return [...this.#state.selected];
    }

    /**
     * Programmatically select items.
     * @param {string|string[]} ids
     */
    select(ids) {
        if (typeof ids === 'string') ids = [ids];
        deselectAll(this.#state);
        clearSelection(this.#canvas);
        for (const id of ids) {
            selectItem(this.#state, id, true);
            markSelected(this.#canvas, id);
        }
        const selected = this.getSelectedItems();
        emitEvent(this.#viewport[0], 'select', { items: selected });
        this.#config.onSelect?.(selected);
    }

    /**
     * Clear selection.
     */
    clearSelection() {
        deselectAll(this.#state);
        clearSelection(this.#canvas);
        emitEvent(this.#viewport[0], 'select', { items: [] });
        this.#config.onSelect?.(this.getSelectedItems());
    }

    /**
     * Set zoom level.
     * @param {number} level
     */
    setZoom(level) {
        this.#zoom = clamp(level, DEFAULTS.minZoom, DEFAULTS.maxZoom);
        updateCanvasTransform(this.#canvas, this.#pan, this.#zoom);
        updateZoomDisplay(this.#zoomInfo, this.#zoom);
    }

    /**
     * Get current zoom level.
     * @returns {number}
     */
    getZoom() {
        return this.#zoom;
    }

    /**
     * Set pan offset.
     * @param {number} x
     * @param {number} y
     */
    setPan(x, y) {
        this.#pan = { x, y };
        updateCanvasTransform(this.#canvas, this.#pan, this.#zoom);
    }

    /**
     * Get current pan.
     * @returns {{ x: number, y: number }}
     */
    getPan() {
        return { ...this.#pan };
    }

    /**
     * Undo last action.
     * @returns {boolean}
     */
    undo() {
        if (undo(this.#state)) {
            this.#rebuildCanvas();
            return true;
        }
        return false;
    }

    /**
     * Redo last undone action.
     * @returns {boolean}
     */
    redo() {
        if (redo(this.#state)) {
            this.#rebuildCanvas();
            return true;
        }
        return false;
    }

    /**
     * Export all items as plain data (for save/load).
     * @returns {object[]}
     */
    exportData() {
        return [...this.#state.items.values()].map(({ id, type, src, x, y, w, h, label, locked, meta }) =>
            ({ id, type, src, x, y, w, h, label, locked, meta })
        );
    }

    /**
     * Import items from data (clears existing items).
     * @param {object[]} data
     */
    importData(data) {
        pushUndo(this.#state);
        // Clear all
        this.#state.items.clear();
        this.#state.selected.clear();
        this.#canvas.find('.' + CLS.ITEM).each(function () { this.remove(); });

        for (const item of data) {
            this.#addItemInternal(item);
        }
    }

    /**
     * Destroy the ArtBoard and clean up all resources.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        if (this.#contextMenu) {
            this.#contextMenu.getControl?.().destroy?.();
        }
        cleanupDOM(this.#board);
        this.#state.items.clear();
        this.#state.selected.clear();
        this.#state.plugins.clear();
    }

    /** The board DOM element. */
    get element() { return this.#board; }

    /** Whether the board has been destroyed. */
    get destroyed() { return this.#destroyed; }

    /**
     * Return a lightweight control handle.
     */
    getControl() {
        const self = this;
        return {
            addImage:     (src, opts) => self.addImage(src, opts),
            addVideo:     (src, opts) => self.addVideo(src, opts),
            removeItem:   (id)       => self.removeItem(id),
            updateItem:   (id, p)    => self.updateItem(id, p),
            getItem:      (id)       => self.getItem(id),
            getItems:     ()         => self.getItems(),
            getSelection: ()         => self.getSelection(),
            getSelectedItems: ()     => self.getSelectedItems(),
            select:       (ids)      => self.select(ids),
            clearSelection: ()       => self.clearSelection(),
            setZoom:      (z)        => self.setZoom(z),
            getZoom:      ()         => self.getZoom(),
            setPan:       (x, y)     => self.setPan(x, y),
            getPan:       ()         => self.getPan(),
            undo:         ()         => self.undo(),
            redo:         ()         => self.redo(),
            use:          (n, p)     => self.use(n, p),
            exportData:   ()         => self.exportData(),
            importData:   (d)        => self.importData(d),
            destroy:      ()         => self.destroy(),
            get element()            { return self.element; },
            get destroyed()          { return self.#destroyed; },
        };
    }
};

export default ArtBoard;
