/**
 * @fileoverview ArtBoard state management — item registry, selection, undo stack.
 * @module module/ArtBoard/state
 */

/**
 * Create a fresh state container for an ArtBoard instance.
 * @returns {object} state object
 */
export function createState() {
    return {
        /** @type {Map<string, object>} item id → item data */
        items: new Map(),

        /** @type {Set<string>} currently selected item IDs */
        selected: new Set(),

        /** z-index counter */
        topZ: 1,

        /** undo/redo stacks (snapshots) */
        undoStack: [],
        redoStack: [],

        /** @type {Map<string, Array>} plugin name → context menu items */
        plugins: new Map(),
    };
}

/**
 * Push a snapshot onto the undo stack (deep-copies item data).
 * @param {object} state
 */
export function pushUndo(state) {
    const snapshot = [];
    for (const [id, item] of state.items) {
        snapshot.push([id, { ...item, meta: item.meta ? { ...item.meta } : {} }]);
    }
    state.undoStack.push(snapshot);
    state.redoStack.length = 0; // clear redo on new action
    if (state.undoStack.length > 50) state.undoStack.shift();
}

/**
 * Undo last action.
 * @param {object} state
 * @returns {boolean} true if undo was applied
 */
export function undo(state) {
    if (!state.undoStack.length) return false;

    // Save current as redo
    const current = [];
    for (const [id, item] of state.items) current.push([id, { ...item }]);
    state.redoStack.push(current);

    const snapshot = state.undoStack.pop();
    state.items.clear();
    for (const [id, item] of snapshot) state.items.set(id, { ...item, meta: item.meta ? { ...item.meta } : {} });
    state.selected.clear();
    return true;
}

/**
 * Redo last undone action.
 * @param {object} state
 * @returns {boolean} true if redo was applied
 */
export function redo(state) {
    if (!state.redoStack.length) return false;

    const current = [];
    for (const [id, item] of state.items) current.push([id, { ...item }]);
    state.undoStack.push(current);

    const snapshot = state.redoStack.pop();
    state.items.clear();
    for (const [id, item] of snapshot) state.items.set(id, { ...item, meta: item.meta ? { ...item.meta } : {} });
    state.selected.clear();
    return true;
}

/**
 * Select an item (optionally additive with shift).
 * @param {object} state
 * @param {string} id
 * @param {boolean} additive
 */
export function selectItem(state, id, additive) {
    if (!additive) state.selected.clear();
    state.selected.add(id);
}

/**
 * Deselect all items.
 * @param {object} state
 */
export function deselectAll(state) {
    state.selected.clear();
}

/**
 * Select all items.
 * @param {object} state
 */
export function selectAll(state) {
    for (const id of state.items.keys()) {
        state.selected.add(id);
    }
}

/**
 * Delete selected items from state.
 * @param {object} state
 * @returns {string[]} deleted IDs
 */
export function deleteSelected(state) {
    const deleted = [...state.selected];
    for (const id of deleted) {
        state.items.delete(id);
    }
    state.selected.clear();
    return deleted;
}

/**
 * Get the next z-index for stacking.
 * @param {object} state
 * @returns {number}
 */
export function nextZ(state) {
    return ++state.topZ;
}
