/**
 * @fileoverview ArtBoard component definition for JIT pipeline.
 *
 * Defines design tokens, state machine, template slots, variants,
 * and custom element metadata for the ArtBoard component.
 *
 * @module module/ArtBoard.def
 */

import razyui from '../index.js';
import { PART } from './ArtBoard/constants.js';

/**
 * The definition object for the ArtBoard component.
 * Contains configuration for tokens, states, templates, variants, and custom elements.
 *
 * @type {Object}
 */
export const ArtBoardDef = {
    /**
     * The name of the component.
     * @type {string}
     */
    name: 'ArtBoard',

    /**
     * The custom element tag name for the component.
     * @type {string}
     */
    tag: 'rui-art-board',

    /**
     * Design tokens specific to the ArtBoard component.
     * These tokens define the visual appearance of the component.
     */
    tokens: {
        prefix: 'ab',
        tokens: {
            'bg':              { ref: 'color.bg-inset',    description: 'Board background' },
            'grid-color':      { value: 'rgba(0,0,0,0.06)', description: 'Grid line colour' },
            'grid-size':       { value: '40px',             description: 'Grid cell size' },
            'item-border':     { ref: 'color.border',       description: 'Item border colour' },
            'item-radius':     { ref: 'radius.md',          description: 'Item border radius' },
            'item-shadow':     { ref: 'shadow.sm',          description: 'Item shadow' },
            'item-bg':         { ref: 'color.bg',           description: 'Item background' },
            'select-color':    { ref: 'color.accent',       description: 'Selection highlight colour' },
            'select-width':    { value: '2px',              description: 'Selection border width' },
            'handle-size':     { value: '8px',              description: 'Resize handle size' },
            'toolbar-bg':      { ref: 'color.bg-raised',    description: 'Toolbar background' },
            'toolbar-border':  { ref: 'color.border',       description: 'Toolbar border' },
            'hover-shadow':    { ref: 'shadow.md',          description: 'Item hover shadow' },
            'btn-hover-bg':    { ref: 'color.bg-hover',     description: 'Toolbar button hover background' },
            'btn-active-bg':   { ref: 'color.bg-active',    description: 'Toolbar button active background' },
            'text':            { ref: 'color.text',         description: 'Text colour' },
            'text-muted':      { ref: 'color.text-muted',   description: 'Muted text colour' },
        },
    },

    /**
     * State machine configuration for the ArtBoard component.
     * Defines the possible states and transitions.
     */
    states: {
        initial: 'idle',
        states: {
            idle:      { on: { SELECT: 'selected', PAN_START: 'panning' } },
            selected:  { on: { DESELECT: 'idle', DRAG_START: 'dragging', RESIZE_START: 'resizing', PAN_START: 'panning' } },
            dragging:  { on: { DRAG_END: 'selected' } },
            resizing:  { on: { RESIZE_END: 'selected' } },
            panning:   { on: { PAN_END: 'idle' } },
        },
        effects: {
            selected(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('ab-has-selection');
            },
            'selected:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('ab-has-selection');
            },
            dragging(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('ab-dragging');
            },
            'dragging:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('ab-dragging');
            },
            panning(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('ab-panning');
            },
            'panning:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('ab-panning');
            },
        },
    },

    /**
     * Template slot definitions for the ArtBoard component.
     * Defines the HTML structure and classes for different parts.
     */
    template: {
        slots: {
            root:       { element: 'div', classes: ['ab-board'] },
            viewport:   { element: 'div', classes: ['ab-viewport'] },
            canvas:     { element: 'div', classes: ['ab-canvas'] },
            item:       { element: 'div', classes: ['ab-item'] },
            toolbar:    { element: 'div', classes: ['ab-toolbar'] },
            handle:     { element: 'div', classes: ['ab-handle'] },
            selection:  { element: 'div', classes: ['ab-selection-box'] },
        },
    },

    jitParts: {
        [PART.BOARD]: PART.BOARD,
        [PART.VIEWPORT]: PART.VIEWPORT,
        [PART.CANVAS]: PART.CANVAS,
        [PART.ITEM]: PART.ITEM,
        [PART.HANDLE]: PART.HANDLE,
        [PART.TOOLBAR]: PART.TOOLBAR,
        [PART.TOOLBAR_BTN]: PART.TOOLBAR_BTN,
        [PART.TOOLBAR_SEP]: PART.TOOLBAR_SEP,
        [PART.ZOOM_INFO]: PART.ZOOM_INFO,
    },

    styles: {},

    /**
     * Variants configuration for the ArtBoard component.
     */
    variants: {
        'grid-visible': { description: 'Show background grid' },
        'snap-to-grid': { description: 'Snap items to grid' },
    },

    /**
     * Observed attributes for the custom element.
     * @type {string[]}
     */
    observedAttrs: ['width', 'height', 'zoom', 'grid', 'snap'],

    /**
     * Mapping of observed attributes to component properties.
     * @type {Object<string, string>}
     */
    attrMap: {
        width:  'width',
        height: 'height',
        zoom:   'zoom',
        grid:   'grid',
        snap:   'snap',
    },
};

export default ArtBoardDef;
